2180	\section{Proof of Theorem~\ref{thm:C} and Corollary~\ref{cor:D}}
2181	\label{sec:CD}
2182	
2183	\subsection{Preliminaries}
2184	\label{subsec:HPKS}
2185	
2186	Let $E$, $p$, and $K$ be as in $\S\ref{sec:Zp-twisted}$, and assume in addition that hypotheses (\ref{eq:intro-Heeg}) and (\ref{eq:intro-disc}) hold. Fix an integral ideal $\mathfrak{N}\subset\mathcal{O}_K$ with $\mathcal{O}_K/\mathfrak{N}=\Z/N\Z$. For each positive integer $m$ prime to $N$, let $K[m]$ be the ring class field of $K$ of conductor $m$, and set
2187	\[
2188	G[m]={\rm Gal}(K[m]/K[1]),\quad\quad\mathcal{G}[m]={\rm Gal}(K[m]/K).
2189	\]
2190	Let also $\mathcal{O}_m=\Z+m\mathcal{O}_K$ be the order of $K$ of conductor $m$.
2191	
2192	By the theory of complex multiplication, the cyclic $N$-isogeny between complex CM elliptic curves
2193	\[
2194	\mathbb{C}/\mathcal{O}_K\rightarrow\mathbb{C}/(\mathfrak{N}\cap\mathcal{O}_m)^{-1}
2195	\]
2196	defines a point $x_m\in X_0(N)(K[m])$, and fixing a modular parameterization $\pi:X_0(N)\rightarrow E$ we define the \emph{Heegner point} of conductor $m$ by   
2197	\[
2198	P[m]:=\pi(x_m)\in E(K[m]).
2199	\]
2200	Building on this construction, one can prove the following result.
2201	
2202	
2203	\begin{theorem}%[Howard]
2204	\label{thm:howard-HPKS}
2205	Assume $E(K)[p]=0$. Then there exists a Kolyvagin system $\kappa^{\rm Hg}\in\mathbf{KS}(\mathbf{T},\mathcal{F}_\Lambda,\cL_E)$ such that $\kappa_1^{\rm Hg}\in\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})$ is nonzero.
2206	\end{theorem}
2207	
2208	\begin{proof} 
2209	Under the additional hypotheses that $p\nmid h_K$, the class number of $K$, and the representation $G_K\rightarrow{\rm Aut}_{\Z_p}(T)$ is surjective, this is \cite[Thm.~2.3.1]{howard}. In the following paragraphs, we explain how to adapt Howard's arguments to our situation. 
2210	
2211	We begin by briefly recalling the construction of $\kappa^{\rm Hg}$ in \cite[\S{2.3}]{howard}. Let $K_k$ be the subfield of $K_\infty$ with $[K_k\colon K]=p^k$. For each $n\in\cN$ set
2212	\[
2213	P_k[n]:={\rm Norm}_{K[np^{d(k)}]/K_k[n]}(P[np^{d(k)}])\in E(K_k[n]),
2214	\]
2215	where $d(k)=\min\{d\in\Z_{\geqslant 0}\colon K_k\subset K[p^{d(k)}]\}$, and $K_k[n]$ denotes the compositum of $K_k$ and $K[n]$. Letting $H_k[n]\subset E(K_k[n])\otimes\Z_p$ be the $\Z_p[{\rm Gal}(K_k[n]/K)]$-submodule generated by $P[n]$ and $P_j[n]$ for $j\leqslant k$, it follows from the Heegner point norm relations \cite[\S{3.1}]{perrinriou} that one can form the $\mathcal{G}(n)$-module
2216	\[
2217	\mathbf{H}[n]:=\varprojlim_k H_k[n].
2218	\]
2219	By \cite[Lem.~2.3.3]{howard}, there is a family 
2220	\[
2221	\{Q[n]=\varprojlim_k Q_k[n]\in\mathbf{H}[n]\}_{n\in\cN}
2222	\]
2223	such that
2224	\begin{equation}\label{eq:multiplier}
2225	Q_0[n]=\Phi P[n],\quad\textrm{where}\;
2226	\Phi=
2227	\left\{
2228	\begin{array}{ll}
2229	(p-a_p\sigma_p+\sigma_p^2)(p-a_p\sigma_p^*+\sigma_p^{*2}) & \textrm{if $p$ splits in $K$,}\\[0.2em]
2230	(p+1)^2-a_p^2 & \textrm{if $p$ is inert in $K$,}
2231	\end{array}
2232	\right.
2233	\end{equation}
2234	with $\sigma_p$ and $\sigma_p^*$ the Frobenius elements at the primes above $p$ in the split case, and 
2235	\[
2236	{\rm Norm}_{K_{\infty}[n\ell]/K_{\infty}[n]}Q[n\ell] = a_{\ell}Q[n] 
2237	\]
2238	for all $n\ell\in\cN$. Letting $D_n\in\Z_p[G(n)]$ be Kolyvagin's derivative operators, and choosing a set $S$ of representatives for $\mathcal{G}(n)/G(n)$, the class $\kappa_n\in \rH^1(K,\mathbf{T}/I_n\mathbf{T})$ is defined as the natural image of 
2239	\begin{equation}\label{eq:Qn}
2240	\tilde{\kappa}_n:=\sum_{s\in S}sD_nQ[n]\in\mathbf{H}[n]
2241	\end{equation}
2242	under the composite map
2243	\[
2244	\bigl(\mathbf{H}[n]/I_n\mathbf{H}[n]\bigr)^{\mathcal{G}(n)}\xrightarrow{\delta(n)}\rH^1(K[n],\mathbf{T}/I_n\mathbf{T})^{\mathcal{G}(n)}\overset{\simeq}\longleftarrow\rH^1(K,\mathbf{T}/I_n\mathbf{T}),
2245	\]
2246	where $\delta(n)$ is induced by the limit of Kummer maps $\delta_k(n):E(K_k[n])\otimes\bZ_p\rightarrow{\rm H}^1(K_k[n],T)$, and the second arrow is given by restriction. (In our case, that the latter is an isomorphism follows from the fact that the extensions $K[n]$ and $\Q(E[p])$ are linearly disjoint, and $E(K_\infty)[p]=0$.) 
2247	
2248	The proof that the classes  $\kappa_n$ land in $\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})$ and can be modified to a system $\kappa^{\rm Hg}=\{\kappa_n^{\rm Hg}\}_{n\in\cN}$ satisfying the Kolyvagin system relations is the same as in \cite[Lem.~2.3.4]{howard} \emph{et seq.}, noting that the arguments proving Lemma~2.3.4 (in the case $v\vert p$) apply almost \emph{verbatim} in the case when $p$ divides the class number of $K$. Finally, that $\kappa_1^{\rm Hg}$ is nonzero follows from the works of Cornut and Vatsal \cite{cornut, vatsal}.
2249	\end{proof}
2250	
2251	Applying Theorem~\ref{thm:howard} and Corollary~\ref{cor:howard} to the Kolyvagin system $\kappa^{\rm Hg}$ of Theorem~\ref{thm:howard-HPKS}, we thus obtain the following.
2252	
2253	\begin{theorem}\label{thm:howard-HP}
2254	Assume $E(K)[p]=0$. Then the module $\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})$ has $\Lambda$-rank one, and there is a finitely generated torsion $\Lambda$-module $M$ such that
2255	\begin{itemize}
2256	\item[(i)] $\mathcal{X}\sim\Lambda\oplus M\oplus M$,
2257	\item[(ii)] ${\rm char}_\Lambda(M)$ divides ${\rm char}_\Lambda\bigl(\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})/\Lambda\kappa_1^{\rm Hg}\bigr)$ in $\Lambda[1/p,1/(\gamma-1)]$.
2258	\end{itemize}
2259	Moreover, if $\rH^1_{\CF}(K,E[p^\infty])$ has $\Z_p$-corank one,  then ${\rm char}_\Lambda(M)$ divides ${\rm char}_\Lambda\bigl(\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})/\Lambda\kappa_1^{\rm Hg}\bigr)$ in $\Lambda[1/p]$.
2260	\end{theorem}
2261	
2262	\begin{remark}\label{rem:comparison}
2263	For our later use, we compare the class $\kappa_1^{\rm Hg}\in\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})$ from Theorem~\ref{thm:howard-HPKS} with the $\Lambda$-adic class constructed in \cite[\S{5.2}]{cas-hsieh1} (taking for $f$ the newform associated with $E$). 
2264	
2265	Denote by $\alpha$ the $p$-adic unit root of $x^2-a_px+p$. With the notations introduced in the proof of Theorem~\ref{thm:howard-HPKS}, define the \emph{$\alpha$-stabilized Heegner point} $P[p^k]_\alpha\in E(K[p^k])\otimes\Z_p$ by 
2266	\begin{equation}\label{eq:stabilized-1}
2267	P[p^k]_\alpha:=\left\{
2268	\begin{array}{ll}
2269	P[p^k]-\alpha^{-1}P[p^{k-1}]&\textrm{if $k\geqslant 1$,}\\[0.2em]
2270	u_K^{-1}\bigl(1-\alpha^{-1}\sigma_p\bigr)\bigl(1-\alpha^{-1}\sigma_p^*\bigr)P[1]&\textrm{if $k=0$ and $p$ splits in $K$,}\\
2271	u_K^{-1}\bigl(1-\alpha^{-2}\bigr)P[1]&\textrm{if $k=0$ and $p$ is inert in $K$.}
2272	\end{array}
2273	\right.
2274	\end{equation}
2275	
2276	Using the Heegner point norm relations, a straightforward calculation shows that the points $\alpha^{-k}P[p^k]_\alpha$ are norm-compatible.  Letting $\delta:E(K_k)\otimes\Z_p\rightarrow\rH^1(K_k,T_pE)$ be the Kummer map, we may therefore set
2277	\[
2278	\kappa_\infty:=\varprojlim_k\delta(\kappa_k)\in\varprojlim_k\rH^1(K_k,T_pE)\simeq\rH^1(K,\mathbf{T}),
2279	\]
2280	where $\kappa_k=\alpha^{-d(k)}{\rm Norm}_{K[p^{d(k)}]/K_k}(P[p^{d(k)}]_\alpha)$. The inclusion $\kappa_\infty\in\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})$ follows immediately from the construction. 
2281	For the comparison with $\kappa_1^{\rm Hg}$, note that by (\ref{eq:Qn}) the projection ${\rm pr}_K({\kappa}_1^{\rm Hg})$ of $\kappa_1^{\rm Hg}$ to $\rH^1(K,T_pE)$ is given by the Kummer image of ${\rm Norm}_{K[1]/K}(Q_0[1])$, while $\kappa_0$ is the Kummer image of ${\rm Norm}_{K[1]/K}(P[1]_\alpha)$. Thus comparing $(\ref{eq:multiplier})$ and $(\ref{eq:stabilized-1})$ we see that 
2282	\begin{equation}\label{eq:comparison}
2283	{\rm pr}_K(\kappa_1^{\rm Hg})=
2284	\begin{cases}
2285	u_K\alpha^2(\beta-1)^2\cdot\kappa_0&\textrm{if $p$ splits in $K$},\\
2286	u_K\alpha^2(\beta^2-1)\cdot\kappa_0&\textrm{if $p$ is inert in $K$,}
2287	\end{cases}
2288	\end{equation}
2289	where $\beta=p\alpha^{-1}$. 
2290	%Since $u_K=1$ by hypothesis (\ref{eq:intro-disc}), 
2291	In particular, $\kappa_\infty$ and $\kappa_1^{\rm Hg}$ generate the same $\Lambda$-submodule of $\rH^1_{\Fcal_\Lambda}(K,\mathbf{T})$. 
2292	\end{remark}
2293	
