4	\chapter{Algebraic Iwasawa Comparison}
5	\label{chap:algebraic-comparison}
6	
7	% archon:covers MR4372220OnTheAnticyclotomicIwasawaTheoryOfRationalEllipticCurvesAtEisensteinPrimes/Algebraic.lean
8	
9	This chapter isolates the algebraic comparison lane. The local Selmer formalism is taken as given: here we only compare the residual decomposition
10	\[
11	E[p]^{ss}\cong \mathbb F_p(\phi)\oplus \mathbb F_p(\psi)
12	\]
13	with the corresponding character Selmer groups, and we record the local Euler-factor bookkeeping that produces the \(\lambda\)-formula for \(\mathfrak X_E\).
14	
15	Throughout, we write
16	\[
17	\mathfrak X_E^S:=\rH^1_{\Fcal_{\rm Gr}^S}(K,M_E)^\vee,
18	\qquad
19	\mathfrak X_E:=\rH^1_{\Fcal_{\rm Gr}}(K,M_E)^\vee,
20	\]
21	and for each split prime \(w\nmid p\) in \(S\) we use
22	\[
23	\mathcal P_w(E)=P_w(\ell^{-1}\gamma_w)\in\Lambda
24	\]
25	for the local Euler factor of \(E\). The character-side modules and Euler factors are supplied by the local Selmer chapter.
26	
27	\section{Residual comparison}
28	
29	\begin{proposition}[Residual comparison for \(E[p]\)]
30	  \label{prop:modp-E}
31	  \lean{MR4372220.Algebraic.residualComparison}
32	  % SOURCE: [MR4372220], Prop.~\ref{cormodp}, §Algebraic side, Selmer groups of E (read from references/MR4372220-anticyclotomic-iwasawa-source/Eisenstein.tex)
33	  % SOURCE QUOTE: "0 \rightarrow \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\phi[p]) \rightarrow \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \rightarrow"
34	  \textit{Source: MR4372220, Selmer groups of E.}
35	  The short exact sequence \(0 \to M_\phi[p] \to M_E[p] \to M_\psi[p] \to 0\) induces a natural exact sequence
36	  \[
37	  0 \to \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\phi[p]) \to \rH^1_{\Fcal_{\rm Gr}^S}(K,M_E[p]) \to
38	  \rH^1_{\Fcal_{\rm Gr}^S}(K,M_\psi[p]) \to 0.
39	  \]
40	  In particular, the imprimitive residual Selmer group of \(E\) is finite, and its \(\mathbb F_p\)-dimension is the sum of the corresponding character dimensions.
41	\end{proposition}
